// ═══════════════════════════════════════════════════════════════════════════════
// SISTEMA DE MARTINGALE (G1, G2)
// ═══════════════════════════════════════════════════════════════════════════════

// Estado do ciclo de Martingale atual
let martingaleState = {
    active: false,                    // Se há um ciclo ativo
    stage: 'ENTRADA',                 // 'ENTRADA' | 'G1' | 'G2'
    patternKey: null,                 // Identificador do padrão atual
    entryColor: null,                 // Cor da entrada inicial (aposta)
    currentColor: null,               // Cor atual do ciclo (pode mudar em G1/G2 quando permitido)
    entryColorResult: null,           // Cor que realmente saiu na entrada
    entryTimestamp: null,             // Timestamp da entrada inicial
    analysisData: null,               // Dados completos da análise
    lossCount: 0,                     // Contador de LOSS consecutivos
    lossColors: [],                   // Array de cores dos giros que deram LOSS
    patternsWithoutHistory: 0         // Contador de padrões sem histórico que deram LOSS
};

// ✅ Diamante (G1/G2): recriar o "raciocínio" (patternDescription) para a fase atual,
// incluindo N4 (re-análise) e exibindo o status das barreiras N7/N8/N9/N10 também no GALE.
// ⚠️ Importante: as barreiras NÃO devem encerrar o ciclo de Martingale — G1/G2 seguem a config de gales.
function buildDiamondGalePhaseAnalysis({ history, phase, preferredColor, fallbackColor, config }) {
    const normalizeColor = (v) => {
        const s = String(v || '').toLowerCase().trim();
        if (!s) return '';
        if (s === 'branco') return 'white';
        if (s.startsWith('w')) return 'white';
        if (s.startsWith('r')) return 'red';
        // "branco" não é black
        if (s.startsWith('b') && s !== 'branco') return 'black';
        return s;
    };
    const oppositeRB = (c) => (c === 'red' ? 'black' : (c === 'black' ? 'red' : c));
    const clamp01Local = (x) => Math.max(0, Math.min(1, Number(x) || 0));
    const fmtPct = (x) => `${(clamp01Local(x) * 100).toFixed(1)}%`;

    const hist = Array.isArray(history) ? history : [];
    const cfg = (config && typeof config === 'object') ? config : analyzerConfig;
    const ph = String(phase || '').toUpperCase().trim() || 'G1';
    const stageNumber = getMartingaleStageNumber(ph) || 1;
    const { maxGales } = getMartingaleSettings('diamond', cfg);

    // 1) N4 (re-análise para o GALE)
    const n4Res = pickN4DynamicGaleResult({
        history: hist,
        config: cfg,
        stageNumber,
        maxGales,
        forcePick: true
    });

    const pref = normalizeColor(preferredColor) || (n4Res && n4Res.color ? normalizeColor(n4Res.color) : '');
    const fallback = normalizeColor(fallbackColor);
    let chosen = (pref === 'red' || pref === 'black' || pref === 'white') ? pref : (fallback || 'red');

    // 2) Validar barreiras N7/N8/N9/N10 para a cor candidata do GALE (por maioria)
    const n7Enabled = isDiamondLevelEnabled('N7', cfg);
    const n8Enabled = isDiamondLevelEnabled('N8', cfg);
    const n9Enabled = isDiamondLevelEnabled('N9', cfg);
    const n10Enabled = isDiamondLevelEnabled('N10', cfg);
    // N7: autoajuste (não usar configuração do usuário)
    const n7DecisionWindow = 20;
    const n7HistoryWindow = 100;
    const n7MaxWindow = Math.max(10, Math.min(50, Math.floor(Number(n7DecisionWindow) || 20)));
    const n7HistWindow = Math.max(n7MaxWindow, Math.min(2000, Math.floor(Number(n7HistoryWindow) || 100)));
    const n8Window = (cfg === analyzerConfig)
        ? getDiamondWindow('n8Barrier1', getDiamondWindow('n8Barrier', 50))
        : getDiamondWindowFromConfig(cfg, 'n8Barrier1', getDiamondWindowFromConfig(cfg, 'n8Barrier', 50));
    const n9Window = (cfg === analyzerConfig)
        ? getDiamondWindow('n8Barrier', 50)
        : getDiamondWindowFromConfig(cfg, 'n8Barrier', 50);
    const n10History = (cfg === analyzerConfig)
        ? getDiamondWindow('n10History', 2000)
        : getDiamondWindowFromConfig(cfg, 'n10History', 2000);

    const evalBarriers = (color) => {
        const c = normalizeColor(color);
        const n7 = n7Enabled
            ? validateN7ApexPercentageBarrier(hist, c, { maxWindow: n7MaxWindow, historyWindow: n7HistWindow })
            : { allowed: true, reason: 'disabled', details: 'DESATIVADO' };
        const n8 = n8Enabled ? validateOppositeContinuationBarrier(hist, c, n8Window, { minStreakToWorry: 3 }) : { allowed: true, reason: 'disabled', details: 'DESATIVADO' };
        const n9 = n9Enabled ? validateSequenceBarrier(hist, c, n9Window, null) : { allowed: true, reason: 'disabled', currentStreak: 0, targetStreak: 0, maxStreakFound: 0 };
        const n10 = n10Enabled ? validateN10IntelligentBarrier(hist, c, { historySize: n10History, minOccurrences: 4 }) : { allowed: true, reason: 'disabled', details: 'DESATIVADO' };
        const votes = [];
        if (n7Enabled) votes.push({ id: 'N7', allowed: n7 && n7.allowed !== false });
        if (n8Enabled) votes.push({ id: 'N8', allowed: n8 && n8.allowed !== false });
        if (n9Enabled) votes.push({ id: 'N9', allowed: n9 && n9.allowed !== false });
        if (n10Enabled) votes.push({ id: 'N10', allowed: n10 && n10.allowed !== false });
        const total = votes.length;
        const approvals = votes.filter(v => v.allowed).length;
        // ✅ Unanimidade (alinhado com as barreiras do sinal principal)
        const needed = total;
        const allowed = total === 0 ? true : approvals >= needed;
        return { allowed, approvals, needed, total, n7, n8, n9, n10 };
    };

    let barriers = evalBarriers(chosen);
    let switchedByBarriers = false;
    // ✅ No GALE, barreiras são INFORMATIVAS (não encerram o Martingale).
    // Porém, no modo consecutivo, se a cor candidata for bloqueada e a oposta for aprovada,
    // ajustamos o sinal para respeitar a leitura das barreiras.
    if (!barriers.allowed && (chosen === 'red' || chosen === 'black')) {
        const opposite = oppositeRB(chosen);
        const oppositeBarriers = evalBarriers(opposite);
        if (oppositeBarriers.allowed) {
            chosen = opposite;
            barriers = oppositeBarriers;
            switchedByBarriers = true;
        }
    }
    const barriersDisapproved = !barriers.allowed;
    const blockedAll = false;

    // 3) Construir reasoning compatível com o parser da UI (content.js)
    const intensityLabel = (cfg && cfg.signalIntensity === 'conservative') ? 'Conservador' : 'Agressivo';
    const p1 = (n4Res && typeof n4Res.p1 === 'number') ? clamp01Local(n4Res.p1) : null;
    const p2 = (n4Res && typeof n4Res.p2 === 'number') ? clamp01Local(n4Res.p2) : null;
    const p3 = (n4Res && typeof n4Res.p3 === 'number') ? clamp01Local(n4Res.p3) : null;
    const confidencePct = (p1 != null) ? Math.round(p1 * 1000) / 10 : 0; // 1 casa
    const scoreCombined = (p1 != null) ? confidencePct : 0;

    const n4Line = (() => {
        const p1Txt = p1 != null ? fmtPct(p1) : 'n/d';
        const p2Txt = p2 != null ? fmtPct(p2) : 'n/d';
        const p3Txt = p3 != null ? fmtPct(p3) : 'n/d';
        const strengthTxt = p1 != null ? `${Math.round(p1 * 100)}%` : '0%';
        const detail = `Entrada ${p1Txt} • Até G1 ${p2Txt} • Até G2 ${p3Txt}`;
        return `N4 - Autointeligente → ${String(chosen).toUpperCase()} (${strengthTxt} • ${detail})`;
    })();

    const n7Line = (() => {
        if (!n7Enabled) return `N7 - Barreira (Ápice %) → DESATIVADO`;
        const n7 = barriers.n7 || {};
        const status = (n7.allowed !== false) ? '✅ APROVADO' : '🚫 BLOQUEADO';
        const detail = (typeof n7.details === 'string' && n7.details.trim()) ? n7.details.trim() : status;
        return `N7 - Barreira (Ápice %) → ${detail}`;
    })();

    const n8Line = (() => {
        if (!n8Enabled) return `N8 - Barreira 1 (Oposta) → DESATIVADO`;
        const n8 = barriers.n8 || {};
        const status = (n8.allowed !== false) ? '✅ APROVADO' : '🚫 BLOQUEADO';
        const detail = (typeof n8.details === 'string' && n8.details.trim()) ? n8.details.trim() : status;
        return `N8 - Barreira 1 (Oposta) → ${detail}`;
    })();

    const n9Line = (() => {
        if (!n9Enabled) return `N9 - Barreira 2 (Indicada) → DESATIVADO`;
        const n9 = barriers.n9 || {};
        const cur = Number(n9.currentStreak ?? 0);
        const target = Number(n9.targetStreak ?? 0);
        const maxHist = Number(n9.maxStreakFound ?? 0);
        const status = (n9.allowed !== false) ? '✅ APROVADO' : '🚫 BLOQUEADO';
        return `N9 - Barreira 2 (Indicada) → ${status} (Atual ${cur} • alvo ${target} • máx ${maxHist}${n9.gapRuleBlocked ? ' (sem folga)' : ''})`;
    })();

    const n10Line = (() => {
        if (!n10Enabled) return `N10 - Barreira Inteligente → DESATIVADO`;
        const n10 = barriers.n10 || {};
        const status = (n10.allowed !== false) ? '✅ APROVADO' : '🚫 BLOQUEADO';
        const detail = (typeof n10.details === 'string' && n10.details.trim()) ? n10.details.trim() : status;
        // ✅ N10 é BARREIRA: mostrar APROVADO/BLOQUEADO (igual N9), sem "Voto:".
        return `N10 - Barreira Inteligente → ${detail}`;
    })();

    const decisionLine =
        `DECISÃO: ${String(chosen).toUpperCase()}` +
        (switchedByBarriers ? ' (ajustada pelas barreiras)' : '') +
        (barriersDisapproved ? ' (⚠️ barreiras reprovaram)' : '');

    const reasoning =
        `${n4Line}\n` +
        `${n7Line}\n` +
        `${n8Line}\n` +
        `${n9Line}\n` +
        `${n10Line}\n` +
        `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n` +
        `Modo: ${intensityLabel}\n` +
        `Score combinado: ${Number(scoreCombined || 0).toFixed(1)}%\n` +
        `${decisionLine}\n` +
        `Confiança: ${Number(confidencePct || 0).toFixed(1)}%`;

    // 4) Montar payload estruturado (AI_ANALYSIS) – é isso que a UI renderiza no topo
    const last10Spins = hist.slice(0, 10).map(spin => ({
        color: spin.color,
        number: spin.number,
        timestamp: spin.timestamp
    }));
    const aiDescriptionData = {
        type: 'AI_ANALYSIS',
        color: chosen,
        confidence: Number(confidencePct || 0),
        diamondSourceLevel: 'N4',
        last10Spins,
        last5Spins: last10Spins.slice(0, 10),
        reasoning,
        historySize: Math.min(Math.max(cfg.aiHistorySize || 50, 20), hist.length),
        galePhase: ph,
        blocked: false,
        blockedReason: null,
        barriersDisapproved: !!barriersDisapproved
    };

    return {
        blockedAll,
        barriersDisapproved: !!barriersDisapproved,
        chosenColor: chosen,
        n4Res,
        n7: barriers.n7,
        n8: barriers.n8,
        n9: barriers.n9,
        n10: barriers.n10,
        confidencePct: Number(confidencePct || 0),
        reasoning,
        patternDescription: JSON.stringify(aiDescriptionData)
    };
}

// ✅ Diamante: mesmo quando NÃO houver sinal, gerar um relatório (raciocínio) para a UI.
// Objetivo: o usuário ver o que está acontecendo por trás (N4 + barreiras N8/N9/N10),
// sem recomendar entrada no topo.
function buildDiamondNoSignalReport({ history, config }) {
    try {
        const normalizeColor = (v) => {
            const s = String(v || '').toLowerCase().trim();
            if (!s) return '';
            if (s === 'branco') return 'white';
            if (s.startsWith('w')) return 'white';
            if (s.startsWith('r')) return 'red';
            if (s.startsWith('b') && s !== 'branco') return 'black';
            return s;
        };
        const clamp01Local = (x) => Math.max(0, Math.min(1, Number(x) || 0));
        const fmtPct = (x) => `${(clamp01Local(x) * 100).toFixed(1)}%`;

        const hist = Array.isArray(history) ? history : [];
        const cfg = (config && typeof config === 'object') ? config : analyzerConfig;

        const { maxGales } = getMartingaleSettings('diamond', cfg);

        // Reusar o mesmo "motor" do N4 (P1/P2/P3) — sem depender de haver Gale.
        const n4Res = pickN4DynamicGaleResult({
            history: hist,
            config: cfg,
            stageNumber: 0, // entrada
            maxGales,
            forcePick: true
        });

        const chosen = (n4Res && n4Res.color) ? normalizeColor(n4Res.color) : '';
        const chosenValid = (chosen === 'red' || chosen === 'black' || chosen === 'white');

        const p1 = (n4Res && typeof n4Res.p1 === 'number') ? clamp01Local(n4Res.p1) : null;
        const p2 = (n4Res && typeof n4Res.p2 === 'number') ? clamp01Local(n4Res.p2) : null;
        const p3 = (n4Res && typeof n4Res.p3 === 'number') ? clamp01Local(n4Res.p3) : null;
        const confidencePct = (p1 != null) ? Math.round(p1 * 1000) / 10 : 0; // 1 casa

        const n4Line = (() => {
            if (!chosenValid) return `N4 - Autointeligente → NULO`;
            const p1Txt = p1 != null ? fmtPct(p1) : 'n/d';
            const p2Txt = p2 != null ? fmtPct(p2) : 'n/d';
            const p3Txt = p3 != null ? fmtPct(p3) : 'n/d';
            const strengthTxt = p1 != null ? `${Math.round(p1 * 100)}%` : '0%';
            const detail = `Entrada ${p1Txt} • Até G1 ${p2Txt} • Até G2 ${p3Txt}`;
            return `N4 - Autointeligente → ${String(chosen).toUpperCase()} (${strengthTxt} • ${detail})`;
        })();

        // Barreiras: sempre rodar e reportar (mesmo sem sinal)
        const n8Enabled = isDiamondLevelEnabled('N8', cfg);
        const n9Enabled = isDiamondLevelEnabled('N9', cfg);
        const n10Enabled = isDiamondLevelEnabled('N10', cfg);
        const n7Enabled = isDiamondLevelEnabled('N7', cfg);
        // N7: autoajuste (não usar configuração do usuário)
        const n7DecisionWindow = 20;
        const n7HistoryWindow = 100;
        const n7MaxWindow = Math.max(10, Math.min(50, Math.floor(Number(n7DecisionWindow) || 20)));
        const n7HistWindow = Math.max(n7MaxWindow, Math.min(2000, Math.floor(Number(n7HistoryWindow) || 100)));
        const n8Window = (cfg === analyzerConfig)
            ? getDiamondWindow('n8Barrier1', getDiamondWindow('n8Barrier', 50))
            : getDiamondWindowFromConfig(cfg, 'n8Barrier1', getDiamondWindowFromConfig(cfg, 'n8Barrier', 50));
        const n9Window = (cfg === analyzerConfig)
            ? getDiamondWindow('n8Barrier', 50)
            : getDiamondWindowFromConfig(cfg, 'n8Barrier', 50);
        const n10History = (cfg === analyzerConfig)
            ? getDiamondWindow('n10History', 2000)
            : getDiamondWindowFromConfig(cfg, 'n10History', 2000);

        const c = chosenValid ? chosen : 'red';
        const n7 = n7Enabled ? validateN7ApexPercentageBarrier(hist, c, { maxWindow: n7MaxWindow, historyWindow: n7HistWindow }) : { allowed: true, details: 'DESATIVADO' };
        const n8 = n8Enabled ? validateOppositeContinuationBarrier(hist, c, n8Window, { minStreakToWorry: 3 }) : { allowed: true, details: 'DESATIVADO' };
        const n9 = n9Enabled ? validateSequenceBarrier(hist, c, n9Window, null) : { allowed: true, currentStreak: 0, targetStreak: 0, maxStreakFound: 0, details: 'DESATIVADO' };
        const n10 = n10Enabled ? validateN10IntelligentBarrier(hist, c, { historySize: n10History, minOccurrences: 4 }) : { allowed: true, details: 'DESATIVADO' };

        const n7Line = (() => {
            if (!n7Enabled) return `N7 - Barreira (Ápice %) → DESATIVADO`;
            const ok = !!(n7 && n7.allowed !== false);
            const status = ok ? '✅ APROVADO' : '🚫 BLOQUEADO';
            const detail = (typeof n7.details === 'string' && n7.details.trim()) ? n7.details.trim() : status;
            return `N7 - Barreira (Ápice %) → ${detail}`;
        })();

        const n8Line = (() => {
            if (!n8Enabled) return `N8 - Barreira 1 (Oposta) → DESATIVADO`;
            const ok = !!(n8 && n8.allowed !== false);
            const status = ok ? '✅ APROVADO' : '🚫 BLOQUEADO';
            const detail = (typeof n8.details === 'string' && n8.details.trim()) ? n8.details.trim() : status;
            return `N8 - Barreira 1 (Oposta) → ${status}${detail && detail !== status ? ` (${detail})` : ''}`;
        })();
        const n9Line = (() => {
            if (!n9Enabled) return `N9 - Barreira 2 (Indicada) → DESATIVADO`;
            const ok = !!(n9 && n9.allowed !== false);
            const status = ok ? '✅ APROVADO' : '🚫 BLOQUEADO';
            const cur = Number(n9.currentStreak ?? 0);
            const target = Number(n9.targetStreak ?? 0);
            const maxHist = Number(n9.maxStreakFound ?? 0);
            return `N9 - Barreira 2 (Indicada) → ${status} (Atual ${cur} • alvo ${target} • máx ${maxHist}${n9.gapRuleBlocked ? ' (sem folga)' : ''})`;
        })();
        const n10Line = (() => {
            if (!n10Enabled) return `N10 - Barreira Inteligente → DESATIVADO`;
            const ok = !!(n10 && n10.allowed !== false);
            const status = ok ? '✅ APROVADO' : '🚫 BLOQUEADO';
            const detail = (typeof n10.details === 'string' && n10.details.trim()) ? n10.details.trim() : status;
            return `N10 - Barreira Inteligente → ${status}${detail && detail !== status ? ` (${detail})` : ''}`;
        })();

        const intensityLabel = (cfg && cfg.signalIntensity === 'conservative') ? 'Conservador' : 'Agressivo';
        const reasoning =
            `${n4Line}\n` +
            `${n7Line}\n` +
            `${n8Line}\n` +
            `${n9Line}\n` +
            `${n10Line}\n` +
            `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n` +
            `Modo: ${intensityLabel}\n` +
            `Score combinado: ${Number(confidencePct || 0).toFixed(1)}%\n` +
            `DECISÃO: NULO\n` +
            `Confiança: ${Number(confidencePct || 0).toFixed(1)}%`;

        const last10Spins = hist.slice(0, 10).map(spin => ({
            color: spin.color,
            number: spin.number,
            timestamp: spin.timestamp
        }));

        const aiDescriptionData = {
            type: 'AI_ANALYSIS',
            color: chosenValid ? chosen : null,
            confidence: Number(confidencePct || 0),
            diamondSourceLevel: 'N4',
            last10Spins,
            last5Spins: last10Spins.slice(0, 10),
            reasoning,
            historySize: Math.min(Math.max(cfg.aiHistorySize || 50, 20), hist.length),
            galePhase: 'G0',
            blocked: true,
            blockedReason: 'no_signal'
        };

        return {
            chosenColor: chosenValid ? chosen : null,
            confidencePct: Number(confidencePct || 0),
            reasoning,
            patternDescription: JSON.stringify(aiDescriptionData),
            n4Res,
            n7,
            n8,
            n9,
            n10
        };
    } catch (_) {
        return null;
    }
}

function calculateGaleConfidenceValue(baseConfidence = 0, analysis = null, state = martingaleState, options = null) {
    const round1 = (value) => Math.round(Number(value) * 10) / 10;
    const clampPct = (value, min = 0, max = 95) => {
        const n = Number(value);
        if (!Number.isFinite(n)) return min;
        return Math.max(min, Math.min(max, n));
    };
    const normColor = (value) => String(value || '').toLowerCase().trim();

    const numericBase = Number.isFinite(Number(baseConfidence)) ? Number(baseConfidence) : 0;

    // Fora de martingale: manter comportamento original
    if (!state || !state.active) {
        return round1(clampPct(numericBase, 0, 95));
    }

    const stageLabel = String(analysis?.phase || state.stage || '').toUpperCase().trim();
    const stageNumber = Math.max(0, getMartingaleStageNumber(stageLabel) || Number(state.lossCount || 0));
    const targetColor = normColor(state.entryColor || analysis?.color);
    // Se não temos cor alvo ou não estamos em G1+ -> devolve base (sem “piso fixo”)
    if (!targetColor || stageNumber <= 0) {
        return round1(clampPct(numericBase, 0, 95));
    }

    const computeWinProbFromCounts = (counts) => {
        if (!counts || typeof counts !== 'object') return null;
        const red = Number(counts.red || 0);
        const black = Number(counts.black || 0);
        const white = Number(counts.white || 0);
        const total = red + black + white;
        if (!Number.isFinite(total) || total <= 0) return null;

        let wins = 0;
        if (targetColor === 'red') wins = red;
        else if (targetColor === 'black') wins = black;
        else if (targetColor === 'white') wins = white;
        else wins = 0;

        const pct = (wins / total) * 100;
        return { pct, wins, total };
    };

    const pickBucketForStage = (historyObj) => {
        if (!historyObj || typeof historyObj !== 'object') return null;
        if (stageNumber === 1) return historyObj.after1Loss || null;
        if (stageNumber === 2) return historyObj.after2Loss || null;
        return null; // hoje rastreamos estatística real apenas até 2 LOSS (G1/G2)
    };

    // 1) Probabilidade real por histórico de GALE (padrão específico e global)
    const patternKey = state.patternKey || null;
    const candidates = [];
    if (patternKey && hotColorsHistory && hotColorsHistory[patternKey]) {
        candidates.push({ key: patternKey, bucket: pickBucketForStage(hotColorsHistory[patternKey]) });
    }
    if (hotColorsHistory && hotColorsHistory.__global__) {
        candidates.push({ key: '__global__', bucket: pickBucketForStage(hotColorsHistory.__global__) });
            }

    const bucketStats = candidates
        .map((c) => ({ key: c.key, stats: computeWinProbFromCounts(c.bucket) }))
        .filter((c) => c.stats && c.stats.total > 0)
        .sort((a, b) => b.stats.total - a.stats.total)[0] || null;

    const p_afterLoss = bucketStats ? clampPct(bucketStats.stats.pct, 0, 95) : null;
    const afterLossSamples = bucketStats ? bucketStats.stats.total : 0;

    // 2) Fallback real: frequência recente no histórico (evita número “fixo”)
    const recentWindow = 200;
    let p_recent = null;
    try {
        const recent = Array.isArray(cachedHistory) ? cachedHistory.slice(0, Math.min(recentWindow, cachedHistory.length)) : [];
        if (recent.length > 0) {
            const counts = { red: 0, black: 0, white: 0 };
            recent.forEach((s) => {
                const c = normColor(s && s.color);
                if (c === 'red' || c === 'black' || c === 'white') counts[c]++;
            });
            const stats = computeWinProbFromCounts(counts);
            if (stats) p_recent = clampPct(stats.pct, 0, 95);
            }
        } catch (_) {
        // ignore
    }

    // 3) Combinar (peso cresce com amostra real de GALE)
    // - se temos muitos exemplos reais após LOSS, confiamos mais neles
    // - senão, usamos principalmente frequência recente (e um pouco da confiança base)
    const w_after = p_afterLoss != null ? Math.min(0.75, afterLossSamples / (afterLossSamples + 25)) : 0;
    const w_recent = (1 - w_after) * 0.70;
    const w_base = (1 - w_after) * 0.30;

    const baseAdj = clampPct(numericBase, 0, 95);
    const recentAdj = p_recent != null ? p_recent : baseAdj;
    const afterAdj = p_afterLoss != null ? p_afterLoss : 0;

    let finalConfidence = (afterAdj * w_after) + (recentAdj * w_recent) + (baseAdj * w_base);

    // Penalizar estágios muito altos (quando configurado >2) para não inflar confiança sem estatística suficiente
    if (stageNumber >= 3) finalConfidence *= 0.92;
    if (stageNumber >= 5) finalConfidence *= 0.88;

    // ✅ Sem piso fixo. Apenas clamp e arredondamento.
    return round1(clampPct(finalConfidence, 0, 95));
}

function resolveEntryConfidenceForUI(primaryAnalysis = null, fallbackAnalysis = null, stageLike = null) {
    const list = [primaryAnalysis, fallbackAnalysis]
        .filter((item) => item && typeof item === 'object');

    const stageRaw = String(
        stageLike
        || (primaryAnalysis && primaryAnalysis.phase)
        || (fallbackAnalysis && fallbackAnalysis.phase)
        || ''
    ).toUpperCase().trim();
    const isGaleStage = /^G\d+$/.test(stageRaw) && stageRaw !== 'G0';

    const values = [];
    for (const item of list) {
        if (isGaleStage) {
            values.push(item.galeConfidence);
            values.push(item.confidence);
            values.push(item.probability);
        } else {
            values.push(item.confidence);
            values.push(item.probability);
            values.push(item.galeConfidence);
        }
    }

    for (const raw of values) {
        const n = Number(raw);
        if (Number.isFinite(n) && n > 0) return n;
    }
    for (const raw of values) {
        const n = Number(raw);
        if (Number.isFinite(n)) return n;
    }
    return 0;
}

