// Histórico de "cores quentes" por padrão
// Estrutura: { "patternKey": { after1Loss: {red: 5, black: 3}, after2Loss: {red: 2, black: 8} } }
let hotColorsHistory = {};

logBanner(`background.js v17 carregado • ${new Date().toLocaleString('pt-BR')}`);

