// ──────────────────────────────────────────────────────────────────────────────
// 🔧 Runtime URLs (Render alternância)
// Chave compartilhada com Admin Panel: da_urls_v1
// Estrutura:
// { authApiOrigins: [...], girosApiOrigins: [...], girosWsOrigins: [...] }
// ──────────────────────────────────────────────────────────────────────────────

const URLS_LOCAL_KEY = 'da_urls_v1';

function normalizeOrigin(raw) {
    const v = String(raw || '').trim();
    if (!v) return '';
    const withoutApi = v.replace(/\/api\/?$/i, '');
    return withoutApi.replace(/\/+$/, '');
}

function normalizeWs(raw) {
    const v = String(raw || '').trim().replace(/\/+$/, '');
    if (!v) return '';
    return v;
}

async function loadUrlsConfig() {
    // Preferir chrome.storage.local (extensão). Fallback: localStorage (web).
    try {
        if (typeof chrome !== 'undefined' && chrome.storage?.local?.get) {
            const result = await new Promise((resolve) => chrome.storage.local.get([URLS_LOCAL_KEY], resolve));
            return (result && result[URLS_LOCAL_KEY]) ? result[URLS_LOCAL_KEY] : null;
        }
    } catch (_) {}

    try {
        const raw = localStorage.getItem(URLS_LOCAL_KEY);
        return raw ? JSON.parse(raw) : null;
    } catch (_) {
        return null;
    }
}

async function saveUrlsConfig(urls) {
    try {
        if (typeof chrome !== 'undefined' && chrome.storage?.local?.set) {
            await new Promise((resolve) => chrome.storage.local.set({ [URLS_LOCAL_KEY]: urls }, resolve));
        }
    } catch (_) {}

    try {
        localStorage.setItem(URLS_LOCAL_KEY, JSON.stringify(urls));
    } catch (_) {}
}

function applyUrlsConfigToApiConfig(urls) {
    if (!urls || typeof urls !== 'object') return;
    const authList = Array.isArray(urls.authApiOrigins) ? urls.authApiOrigins : [];
    const girosList = Array.isArray(urls.girosApiOrigins) ? urls.girosApiOrigins : [];
    const wsList = Array.isArray(urls.girosWsOrigins) ? urls.girosWsOrigins : [];

    // ✅ Preferir servidor ativo (Admin Panel) quando disponível
    const activeId = String(urls.runtimeActiveServerId || urls.activeServerId || '').trim();
    const servers = Array.isArray(urls.servers) ? urls.servers : [];
    let activeServer = null;
    if (activeId && servers.length) {
        activeServer = servers.find((s) => {
            const sid = String(s?.id || s?.serverId || '').trim();
            return sid && sid === activeId;
        }) || null;
    }

    const auth = normalizeOrigin(activeServer?.authOrigin) || normalizeOrigin(authList[0]);
    const giros = normalizeOrigin(activeServer?.girosOrigin) || normalizeOrigin(girosList[0]);
    const wsFromServer = activeServer?.wsOrigin || activeServer?.girosWsOrigin || activeServer?.girosWsURL || activeServer?.wsURL || null;
    const ws = normalizeWs(wsFromServer) || normalizeWs(wsList[0]);

    if (auth) API_CONFIG.authURL = auth;
    if (giros) API_CONFIG.baseURL = giros;

    if (ws) {
        API_CONFIG.wsURL = ws;
    } else if (giros) {
        try {
            const u = new URL(giros);
            API_CONFIG.wsURL = `wss://${u.host}`;
        } catch (_) {}
    }
}

// Fallback (primeiro acesso/sem cache). Depois do primeiro sync, vem do banco via /api/site/urls.
const FALLBACK_ORIGINS = {
    auth: [
        'https://blaze-analyzer-api-v2-p9xb.onrender.com',
        'https://blaze-analyzer-api-v2-z8s3.onrender.com',
        'https://blaze-analyzer-api-v2.onrender.com'
    ],
    giros: [
        'https://blaze-giros-api-v2-7t0l.onrender.com',
        'https://blaze-giros-api-v2-1.onrender.com'
    ]
};

function getCandidateAuthOrigins(cfg) {
    const activeId = String(cfg?.runtimeActiveServerId || cfg?.activeServerId || '').trim();
    let activeOrigin = '';
    if (activeId && Array.isArray(cfg?.servers)) {
        const activeServer = cfg.servers.find((s) => String(s?.id || s?.serverId || '').trim() === activeId);
        activeOrigin = normalizeOrigin(activeServer?.authOrigin);
    }
    const fromArray = Array.isArray(cfg?.authApiOrigins) ? cfg.authApiOrigins : [];
    const fromServers = Array.isArray(cfg?.servers) ? cfg.servers.map((s) => s?.authOrigin) : [];
    const combined = [activeOrigin, ...fromArray, ...fromServers, ...FALLBACK_ORIGINS.auth]
        .map(normalizeOrigin)
        .filter(Boolean);
    return [...new Set(combined)];
}

// Busca URLs de um servidor específico
async function fetchUrlsFrom(origin) {
    try {
        const url = `${origin}/api/site/urls`;
        const controller = (typeof AbortController !== 'undefined') ? new AbortController() : null;
        const timeoutId = controller ? setTimeout(() => controller.abort(), 5000) : null;

        const resp = await fetch(url, controller
            ? { cache: 'no-store', signal: controller.signal }
            : { cache: 'no-store' }
        ).finally(() => { if (timeoutId) clearTimeout(timeoutId); });
        if (!resp.ok) return null;
        const data = await resp.json();
        return data.success && data.urls ? data.urls : null;
    } catch (_) {
        return null;
    }
}

// Auto-Discovery: tenta todos os servidores conhecidos
async function autoDiscoverUrls() {
    let cached = null;
    try {
        cached = await loadUrlsConfig();
    } catch (_) {}

    const candidates = getCandidateAuthOrigins(cached);
    for (const origin of candidates) {
        const urls = await fetchUrlsFrom(origin);
        if (urls) return urls;
    }

    return null;
}

async function refreshUrlsFromServer() {
    // Tenta auto-discovery se a authURL atual não funcionar
    try {
        let authOrigin = normalizeOrigin(API_CONFIG.authURL);
        if (!authOrigin) return;
        
        // Tenta a URL configurada primeiro
        const configUrl = `${authOrigin}/api/site/urls`;
        let resp = null;
        try {
            const controller = (typeof AbortController !== 'undefined') ? new AbortController() : null;
            const timeoutId = controller ? setTimeout(() => controller.abort(), 5000) : null;
            resp = await fetch(configUrl, controller
                ? { cache: 'no-store', signal: controller.signal }
                : { cache: 'no-store' }
            ).finally(() => { if (timeoutId) clearTimeout(timeoutId); });
        } catch (_) {
            resp = null;
        }
        
        // Se falhar, faz auto-discovery
        if (!resp || !resp.ok) {
            console.log('🔍 Auth URL não respondeu, iniciando auto-discovery...');
            const urls = await autoDiscoverUrls();
            if (urls) {
                const runtimeActiveId = String(urls.runtimeActiveServerId || urls.activeServerId || '').trim() || null;
                const merged = {
                    authApiOrigins: Array.isArray(urls.authApiOrigins) ? urls.authApiOrigins.map(normalizeOrigin).filter(Boolean) : [],
                    girosApiOrigins: Array.isArray(urls.girosApiOrigins) ? urls.girosApiOrigins.map(normalizeOrigin).filter(Boolean) : [],
                    girosWsOrigins: Array.isArray(urls.girosWsOrigins) ? urls.girosWsOrigins.map(normalizeWs).filter(Boolean) : [],
                    servers: Array.isArray(urls.servers) ? urls.servers : [],
                    activeServerId: runtimeActiveId,
                    runtimeActiveServerId: runtimeActiveId,
                    updatedAt: urls.updatedAt || null
                };
                if (merged.authApiOrigins.length || merged.girosApiOrigins.length || merged.girosWsOrigins.length) {
                    await saveUrlsConfig(merged);
                    applyUrlsConfigToApiConfig(merged);
                }
            }
            return;
        }

        // Se a URL configurada funciona, processa normalmente
        const data = await resp.json().catch(() => ({}));
        if (!data.success || !data.urls) return;

        const urls = data.urls || {};
        const runtimeActiveId = String(urls.runtimeActiveServerId || urls.activeServerId || '').trim() || null;
        const merged = {
            authApiOrigins: Array.isArray(urls.authApiOrigins) ? urls.authApiOrigins.map(normalizeOrigin).filter(Boolean) : [],
            girosApiOrigins: Array.isArray(urls.girosApiOrigins) ? urls.girosApiOrigins.map(normalizeOrigin).filter(Boolean) : [],
            girosWsOrigins: Array.isArray(urls.girosWsOrigins) ? urls.girosWsOrigins.map(normalizeWs).filter(Boolean) : [],
            servers: Array.isArray(urls.servers) ? urls.servers : [],
            activeServerId: runtimeActiveId,
            runtimeActiveServerId: runtimeActiveId,
            updatedAt: urls.updatedAt || null
        };
        if (merged.authApiOrigins.length || merged.girosApiOrigins.length || merged.girosWsOrigins.length) {
            await saveUrlsConfig(merged);
            applyUrlsConfigToApiConfig(merged);
        }
    } catch (_) {}
}

const API_CONFIG = {
    // API de Giros (coleta automática, histórico, WebSocket)
    baseURL: 'https://blaze-giros-api-v2-7t0l.onrender.com',
    wsURL: 'wss://blaze-giros-api-v2-7t0l.onrender.com',
    
    // API de Autenticação (usuários, admin, padrões customizados)
    authURL: 'https://blaze-analyzer-api-v2-p9xb.onrender.com',
    
    enabled: true,  // Ativar/desativar sincronização
    syncInterval: 5 * 60 * 1000,  // Sincronizar a cada 5 minutos
    timeout: 10000,  // Timeout de 10 segundos
    retryAttempts: 3,
    useWebSocket: true  // ✅ Usar WebSocket ao invés de polling
};

// ✅ Pedido do usuário (Premium / modo padrão):
// Proibir envio de sinal de entrada com confiança abaixo desse piso.
// (Regra é fixa: <45% = bloqueado)
const MIN_PREMIUM_ENTRY_CONFIDENCE_PCT = 45;

function normalizeConfidencePct(value) {
    const n = Number(value);
    if (!Number.isFinite(n)) return null;
    // Alguns módulos podem produzir 0..1; normalizar para 0..100
    const pct = (n > 0 && n <= 1) ? (n * 100) : n;
    return Math.max(0, Math.min(100, pct));
}

async function blockPremiumLowConfidenceSignal(confPct, reason = 'low_confidence') {
    try {
        const shown = Number.isFinite(confPct) ? Math.round(confPct) : null;
        const msg = shown != null
            ? `⛔ Sinal bloqueado: confiança ${shown}% < ${MIN_PREMIUM_ENTRY_CONFIDENCE_PCT}%`
            : `⛔ Sinal bloqueado: confiança < ${MIN_PREMIUM_ENTRY_CONFIDENCE_PCT}%`;
        try { sendAnalysisStatus(msg); } catch (_) {}
    } catch (_) {}
    try {
        await chrome.storage.local.set({ analysis: null, pattern: null });
    } catch (_) {}
    try { sendMessageToContent('CLEAR_ANALYSIS'); } catch (_) {}
    return { blocked: true, reason };
}

// Inicializar config dinâmica (sem travar o bootstrap)
(async () => {
    try {
        const urls = await loadUrlsConfig();
        applyUrlsConfigToApiConfig(urls);
        // Buscar do servidor (fonte de verdade) e persistir
        await refreshUrlsFromServer();

        // 💎 Carregar cache local (rápido) e depois buscar do servidor (fonte de verdade)
        try {
            const cachedLevels = await loadDiamondVisibleLevelsConfig();
            if (cachedLevels) {
                diamondAdminVisibleLevels = normalizeDiamondVisibleLevelsMap(cachedLevels);
                diamondAdminVisibleLevelsUpdatedAt = Date.now();
            }
        } catch (_) {}
        refreshDiamondVisibleLevelsFromServer().catch(() => {});
    } catch (_) {}
})();

let apiStatus = {
    isOnline: false,
    lastSync: null,
    lastError: null,
    syncAttempts: 0
};

// ═══════════════════════════════════════════════════════════════════════════════
// 🔌 WEBSOCKET - CONEXÃO EM TEMPO REAL
// ═══════════════════════════════════════════════════════════════════════════════

let ws = null;
let wsReconnectTimeout = null;
let wsHeartbeatInterval = null;
let lastDataReceived = Date.now(); // ✅ Rastrear último dado recebido
let pollingInterval = null; // ✅ Intervalo de polling de fallback
let dataCheckInterval = null; // ✅ Intervalo para verificar dados desatualizados

// ═══════════════════════════════════════════════════════════════════════════════
// ⚡ FAST LANE (cliente): reduzir latência percebida do giro
// - Mesmo com WS ativo, o servidor pode ter 1–3s de atraso.
// - Estratégia: perto do instante esperado do próximo giro (~30s), buscar direto da Blaze (recent/1)
//   com cache-bust e publicar IMEDIATAMENTE se vier mais novo.
// ═══════════════════════════════════════════════════════════════════════════════

// ✅ Importante (web vs extensão):
// Quando este script roda no site (ex.: https://doubleanalyzer.com.br), qualquer fetch direto para
// https://blaze.bet.br/... é bloqueado por CORS e spamma o console, além de quebrar o fallback.
// Em MV3 (service worker da extensão), não existe window/document e o fetch direto pode funcionar
// (host_permissions).
function isBlazeDirectFetchAllowed() {
    try {
        const hasChrome = (typeof chrome !== 'undefined') && chrome && chrome.runtime;
        const hasManifest = hasChrome && (typeof chrome.runtime.getManifest === 'function');
        const noDom = (typeof window === 'undefined') && (typeof document === 'undefined');
        return !!(hasManifest && noDom);
    } catch (_) {
        return false;
    }
}

let fastLaneStartTimeout = null;
let fastLaneStopTimeout = null;
let fastLaneTickTimeout = null;
let fastLaneInFlight = false;
let fastLaneExpectedNextMs = null;

function clearFastLaneTimers() {
    try { if (fastLaneStartTimeout) clearTimeout(fastLaneStartTimeout); } catch (_) {}
    try { if (fastLaneStopTimeout) clearTimeout(fastLaneStopTimeout); } catch (_) {}
    try { if (fastLaneTickTimeout) clearTimeout(fastLaneTickTimeout); } catch (_) {}
    fastLaneStartTimeout = null;
    fastLaneStopTimeout = null;
    fastLaneTickTimeout = null;
}

function computeNextSpinBoundaryMs(lastSpinMs) {
    try {
        const ms = Number(lastSpinMs) || 0;
        if (!Number.isFinite(ms) || ms <= 0) return null;
        const d = new Date(ms);
        const sec = d.getSeconds();
        const next = new Date(d);
        next.setMilliseconds(0);
        if (sec < 30) {
            next.setSeconds(30);
        } else {
            next.setMinutes(next.getMinutes() + 1);
            next.setSeconds(0);
        }
        return next.getTime();
    } catch (_) {
        return null;
    }
}

async function fetchLatestSpinDirectFromBlaze({ timeoutMs = 1600 } = {}) {
    // ❌ No modo web, isso SEMPRE dá CORS. Só permitir no service worker da extensão.
    if (!isBlazeDirectFetchAllowed()) return null;
    const controller = (typeof AbortController !== 'undefined') ? new AbortController() : null;
    const timeoutId = controller ? setTimeout(() => controller.abort(), Math.max(600, Math.floor(Number(timeoutMs) || 1600))) : null;
    try {
        // cache-bust: garante que não vem resposta antiga por cache intermediário
        const url = `https://blaze.bet.br/api/singleplayer-originals/originals/roulette_games/recent/1?cb=${Date.now()}`;
        const resp = await fetch(url, {
            method: 'GET',
            headers: {
                'accept': 'application/json',
                'cache-control': 'no-cache'
            },
            cache: 'no-store',
            signal: controller ? controller.signal : undefined
        }).finally(() => { if (timeoutId) clearTimeout(timeoutId); });
        if (!resp.ok) return null;
        const dataArr = await resp.json().catch(() => null);
        const latest = Array.isArray(dataArr) && dataArr.length ? dataArr[0] : null;
        if (!latest) return null;
        const rollNumber = Number(latest.roll);
        if (!Number.isFinite(rollNumber)) return null;
        const rollColor = getColorFromNumber(Math.floor(rollNumber));
        const createdAt = latest.created_at ?? latest.createdAt ?? latest.timestamp ?? null;
        if (!createdAt) return null;
        return {
            id: `spin_${createdAt}`,
            number: Math.floor(rollNumber),
            color: rollColor,
            timestamp: createdAt,
            created_at: createdAt,
            __source: 'blaze_direct'
        };
    } catch (_) {
        return null;
    } finally {
        try { if (timeoutId) clearTimeout(timeoutId); } catch (_) {}
    }
}

async function fastLaneTick() {
    try {
        if (fastLaneTickTimeout) {
            try { clearTimeout(fastLaneTickTimeout); } catch (_) {}
            fastLaneTickTimeout = null;
        }
        if (!fastLaneExpectedNextMs) return;
        const now = Date.now();
        const expected = Number(fastLaneExpectedNextMs) || 0;
        if (!expected || !Number.isFinite(expected)) return;
        // se ainda estiver muito cedo, reagendar
        if (now < expected - 2500) {
            fastLaneTickTimeout = setTimeout(fastLaneTick, 800);
            return;
        }
        if (fastLaneInFlight) {
            fastLaneTickTimeout = setTimeout(fastLaneTick, 120);
            return;
        }
        fastLaneInFlight = true;
        const spin = await fetchLatestSpinDirectFromBlaze({ timeoutMs: 1200 });
        fastLaneInFlight = false;
        if (spin) {
            // processNewSpinFromServer já dedupa pelo timestamp/número
            detachPromise(processNewSpinFromServer(spin), 'fastlane_process_spin');
        }
        // frequência adaptativa: mais rápido no "miolo" (expected..expected+3s)
        const after = Date.now();
        const delta = after - expected;
        const delay = (delta >= -1500 && delta <= 3000) ? 220 : 650;
        fastLaneTickTimeout = setTimeout(fastLaneTick, delay);
    } catch (_) {
        fastLaneInFlight = false;
        fastLaneTickTimeout = setTimeout(fastLaneTick, 800);
    }
}

function armFastLaneForNextSpin(latestSpinTimestampLike) {
    // ❌ No modo web, não armar Fast Lane (evita CORS spam).
    if (!isBlazeDirectFetchAllowed()) return;
    try {
        const lastMs = parseSpinTimestamp({ timestamp: latestSpinTimestampLike, created_at: latestSpinTimestampLike }) || parseSpinTimestamp({ timestamp: latestSpinTimestampLike }) || Number(latestSpinTimestampLike) || 0;
        const nextMs = computeNextSpinBoundaryMs(lastMs);
        if (!nextMs) return;
        fastLaneExpectedNextMs = nextMs;
        clearFastLaneTimers();
        // armar ~1.2s antes do "boundary" para compensar RTT
        const startIn = Math.max(200, Math.min(40000, (nextMs - Date.now()) - 1200));
        fastLaneStartTimeout = setTimeout(() => {
            // rodar burst por ~8s (cobre atrasos e variações)
            fastLaneStopTimeout = setTimeout(() => {
                clearFastLaneTimers();
                fastLaneExpectedNextMs = null;
            }, 8000);
            fastLaneTick();
        }, startIn);
    } catch (_) {}
}

// Conectar ao WebSocket
function connectWebSocket() {
    if (!API_CONFIG.enabled || !API_CONFIG.useWebSocket) {
        console.log('⚠️ WebSocket desabilitado na configuração');
        return;
    }
    
    if (ws && (ws.readyState === WebSocket.CONNECTING || ws.readyState === WebSocket.OPEN)) {
        console.log('⚠️ WebSocket já conectado ou conectando');
        return;
    }
    
    console.log('║  🔌 CONECTANDO AO WEBSOCKET...                            ║');
    console.log(`║  URL: ${API_CONFIG.wsURL}                               `);
    
    try {
        ws = new WebSocket(API_CONFIG.wsURL);
        
        ws.onopen = () => {
            console.log('✅ WebSocket conectado com sucesso!');
            console.log('⚡ Aguardando giros em TEMPO REAL...');
            apiStatus.isOnline = true;
            apiStatus.lastSync = new Date().toISOString();
            
            // Limpar timeout de reconexão se existir
            if (wsReconnectTimeout) {
                clearTimeout(wsReconnectTimeout);
                wsReconnectTimeout = null;
            }
            
            // ✅ Parar polling de fallback (WebSocket reconectado)
            stopPollingFallback();
            
            // Iniciar heartbeat (responder a PING do servidor)
            startWebSocketHeartbeat();
        };
        
        ws.onmessage = async (event) => {
            try {
                const message = JSON.parse(event.data);
                console.log('📨 Mensagem WebSocket recebida:', message.type);
                // ⚠️ Importante:
                // Não tratar PING/PONG/CONNECTED como "dado novo".
                // O watchdog de "dados desatualizados" deve medir GIROS realmente processados,
                // senão o WS pode ficar "vivo" (PONG OK) mas sem entregar NEW_SPIN e a UI congela.
                
                switch (message.type) {
                    case 'CONNECTED':
                        console.log('✅ Confirmação de conexão:', message.message);
                        console.log(`📊 Clientes conectados: ${message.clientsConnected}`);
                        break;
                        
                    case 'INITIAL_DATA':
                        console.log('📊 Dados iniciais recebidos');
                        if (message.data && message.data.lastSpin) {
                            await processNewSpinFromServer(message.data.lastSpin);
                        }
                        break;
                        
                    case 'NEW_SPIN':
                        // ✅ NOVO GIRO EM TEMPO REAL!
                        console.log('🎯 NOVO GIRO RECEBIDO VIA WEBSOCKET!', message.data);
                        await processNewSpinFromServer(message.data);
                        break;
                        
                    case 'PING':
                        // Servidor enviou PING, responder com PONG
                        if (ws && ws.readyState === WebSocket.OPEN) {
                            ws.send(JSON.stringify({ type: 'PONG', timestamp: new Date().toISOString() }));
                        }
                        break;
                        
                    case 'PONG':
                        // Resposta do servidor ao nosso PING
                        console.log('💚 PONG recebido do servidor');
                        break;
                        
                    default:
                        console.log('⚠️ Tipo de mensagem desconhecido:', message.type);
                }
            } catch (error) {
                console.error('❌ Erro ao processar mensagem WebSocket:', error);
            }
        };
        
        ws.onerror = (error) => {
            console.error('❌ Erro WebSocket:', error);
            apiStatus.isOnline = false;
            apiStatus.lastError = new Date().toISOString();
        };
        
        ws.onclose = (event) => {
            console.log('❌ WebSocket desconectado');
            console.log(`   Código: ${event.code}, Motivo: ${event.reason || 'Não especificado'}`);
            apiStatus.isOnline = false;
            
            // Parar heartbeat
            stopWebSocketHeartbeat();
            
            // ✅ Iniciar polling de fallback imediatamente
            startPollingFallback();
            
            // ✅ Tentar reconectar após 2 segundos (reduzido de 5s)
            console.log('⏳ Tentando reconectar em 2 segundos...');
            wsReconnectTimeout = setTimeout(() => {
                console.log('🔄 Tentando reconectar WebSocket...');
                connectWebSocket();
            }, 2000);
        };
        
    } catch (error) {
        console.error('❌ Erro ao criar conexão WebSocket:', error);
        apiStatus.isOnline = false;
        
        // ✅ Iniciar polling de fallback imediatamente
        startPollingFallback();
        
        // ✅ Tentar reconectar após 2 segundos (reduzido de 5s)
        wsReconnectTimeout = setTimeout(() => {
            connectWebSocket();
        }, 2000);
    }
}

// Desconectar WebSocket
function disconnectWebSocket() {
    console.log('⏸️ Desconectando WebSocket...');
    
    if (wsReconnectTimeout) {
        clearTimeout(wsReconnectTimeout);
        wsReconnectTimeout = null;
    }
    
    stopWebSocketHeartbeat();
    
    if (ws) {
        ws.close(1000, 'Desconexão normal');
        ws = null;
    }
}

// Heartbeat - enviar PING ativo do cliente a cada 20s
function startWebSocketHeartbeat() {
    stopWebSocketHeartbeat(); // Limpar qualquer heartbeat anterior
    
    // ✅ Enviar PING ativo do cliente a cada 20 segundos
    wsHeartbeatInterval = setInterval(() => {
        if (ws && ws.readyState === WebSocket.OPEN) {
            try {
                ws.send(JSON.stringify({ type: 'PING', timestamp: Date.now() }));
                console.log('💓 Heartbeat: PING enviado');
            } catch (error) {
                console.error('❌ Erro ao enviar PING:', error);
                // Se falhou ao enviar PING, tentar reconectar
                connectWebSocket();
            }
        } else {
            console.warn('⚠️ WebSocket não está aberto. Tentando reconectar...');
            connectWebSocket();
        }
    }, 20000); // 20 segundos
}

function stopWebSocketHeartbeat() {
    if (wsHeartbeatInterval) {
        clearInterval(wsHeartbeatInterval);
        wsHeartbeatInterval = null;
    }
}

// ═══════════════════════════════════════════════════════════════════════════════
// 🔄 POLLING DE FALLBACK - Quando WebSocket falha ou está inativo
// ═══════════════════════════════════════════════════════════════════════════════

function startPollingFallback() {
    // Se já está rodando, não iniciar novamente
    if (pollingInterval) return;
    
    console.log('%c║  🔄 POLLING DE FALLBACK ATIVADO                          ║', 'color: #FFA500; font-weight: bold;');
    console.log('%c║  WebSocket está offline - buscando dados via HTTP       ║', 'color: #FFA500;');
    console.log('%c║  Frequência: a cada 2 segundos                          ║', 'color: #FFA500;');
    
    // ✅ Notificar content.js que WebSocket caiu
    sendMessageToContent('WEBSOCKET_STATUS', { connected: false });
    
    // ✅ Buscar dados a cada 2 segundos quando WebSocket está offline
    pollingInterval = setInterval(async () => {
        try {
            // Buscar último giro do servidor
            {
                const url = `${API_CONFIG.baseURL}/api/giros/latest`;
                const controller = (typeof AbortController !== 'undefined') ? new AbortController() : null;
                const timeoutId = controller ? setTimeout(() => controller.abort(), 5000) : null;
                // ✅ no-store: evita cache intermediário causando "giro atrasado"
                var response = await fetch(url, controller ? {
                    signal: controller.signal,
                    cache: 'no-store',
                    headers: { 'cache-control': 'no-cache', 'accept': 'application/json' }
                } : { cache: 'no-store', headers: { 'cache-control': 'no-cache', 'accept': 'application/json' } })
                    .finally(() => { if (timeoutId) clearTimeout(timeoutId); });
            }
            
            if (response.ok) {
                const data = await response.json();
                if (data.success && data.data) {
                    await processNewSpinFromServer(data.data);
                }
            }
        } catch (error) {
            console.warn('⚠️ Polling fallback: erro ao buscar dados:', error.message);
        }
    }, 2000); // A cada 2 segundos
}

function stopPollingFallback() {
    if (pollingInterval) {
        clearInterval(pollingInterval);
        pollingInterval = null;
        console.log('✅ Polling de fallback parado - WebSocket reconectado');
        
        // ✅ Notificar content.js que WebSocket reconectou
        sendMessageToContent('WEBSOCKET_STATUS', { connected: true });
    }
}

// ═══════════════════════════════════════════════════════════════════════════════
// 🔍 VERIFICAÇÃO DE DADOS DESATUALIZADOS - Critical para mobile
// ═══════════════════════════════════════════════════════════════════════════════

function startDataFreshnessCheck() {
    // Se já está rodando, não iniciar novamente
    if (dataCheckInterval) return;
    
    console.log('   Verificará se dados estão atualizados a cada 30 segundos');
    
    // ✅ Verificar a cada 30 segundos se os dados estão desatualizados
    dataCheckInterval = setInterval(async () => {
        const now = Date.now();
        const timeSinceLastData = now - lastDataReceived;
        const maxStaleTime = 90000; // 90 segundos (1.5 minutos)
        
        if (timeSinceLastData > maxStaleTime) {
            console.warn('');
            console.warn('%c⚠️⚠️⚠️ DADOS DESATUALIZADOS DETECTADOS! ⚠️⚠️⚠️', 'color: #FF0000; font-weight: bold; font-size: 16px; background: #330000; padding: 5px;');
            console.warn(`   Último dado recebido há ${Math.floor(timeSinceLastData / 1000)} segundos`);
            console.warn('   Forçando reconexão e atualização...');
            console.warn('');

            // ✅ Se o admin trocou o servidor ativo, tentar puxar /api/site/urls antes de reconectar
            // (isso evita ficar "preso" no Render antigo mesmo com WS vivo)
            try { await refreshUrlsFromServer(); } catch (_) {}
            
            // ✅ Forçar reconexão WebSocket
            disconnectWebSocket();
            connectWebSocket();
            
            // ✅ Forçar busca imediata de dados via polling
            detachPromise(collectDoubleData(), 'freshness_collect_latest');
        }
    }, 30000); // Verificar a cada 30 segundos
}

function stopDataFreshnessCheck() {
    if (dataCheckInterval) {
        clearInterval(dataCheckInterval);
        dataCheckInterval = null;
    }
}

// ═══════════════════════════════════════════════════════════════════════════════
// VERIFICAÇÃO DE ABA DA BLAZE - GARANTIR QUE EXTENSÃO SÓ FUNCIONE COM PÁGINA ABERTA
// ═══════════════════════════════════════════════════════════════════════════════

// Verificar se há uma aba da Blaze aberta
async function hasBlazeTabOpen() {
    try {
        const tabs = await chrome.tabs.query({});
        
        const blazeTabs = tabs.filter(tab => {
            if (!tab.url) return false;
            
            // ✅ Aceitar múltiplos domínios da Blaze
            const blazeDomains = [
                'blaze.com',
                'blaze1.space',
                'blaze-1.com',
                'blaze-bet.com',
                'blaze.bet.br'
            ];
            
            return blazeDomains.some(domain => tab.url.includes(domain));
        });
        
        return blazeTabs.length > 0;
    } catch (e) {
        console.error('Erro ao verificar abas da Blaze:', e);
        return false;
    }
}

// Fazer requisição com timeout e retry
async function fetchWithTimeout(url, options = {}, timeout = API_CONFIG.timeout) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);
    
    try {
        const response = await fetch(url, {
            ...options,
            signal: controller.signal
        });
        clearTimeout(timeoutId);
        return response;
    } catch (error) {
        clearTimeout(timeoutId);
        // Melhorar mensagem de erro quando for timeout
        if (error.name === 'AbortError') {
            throw new Error(`Timeout após ${timeout/1000}s - Servidor não respondeu a tempo`);
        }
        throw error;
    }
}

// Verificar se API está online
async function checkAPIStatus() {
    if (!API_CONFIG.enabled) {
        console.log('⚠️ API DESATIVADA - Sincronização offline');
        return false;
    }
    
    try {
        // Usar timeout maior para conexão inicial (20s)
        const response = await fetchWithTimeout(`${API_CONFIG.baseURL}/api/status`, {}, 20000);
        if (response.ok) {
            const data = await response.json();
            apiStatus.isOnline = true;
            apiStatus.lastError = null;
            apiStatus.lastSync = new Date().toISOString();
            console.log('%c✅ API ONLINE - Sincronização ativada!', 'color: #00ff00; font-weight: bold; font-size: 14px;');
            console.log(`📊 Servidor: ${data.database?.giros || 0} giros, ${data.database?.padroes || 0} padrões`);
            return true;
        }
    } catch (error) {
        apiStatus.isOnline = false;
        apiStatus.lastError = error.message;
        // Não mostrar erro se for timeout inicial - servidor pode estar em cold start
        if (error.message.includes('Timeout')) {
            console.log('%c⏳ Servidor demorando (cold start) - Tentará novamente...', 'color: #FFAA00; font-weight: bold;');
        } else {
            console.log('%c❌ API OFFLINE - Modo local ativado', 'color: #ff0000; font-weight: bold; font-size: 14px;');
            console.log(`⚠️ Erro: ${error.message}`);
        }
    }
    return false;
}

// Buscar giros do servidor
// - Default: REALTIME_HISTORY_CAP (uso do modo real / cache em memória)
// - Para simulações/otimizações: pode pedir até REALTIME_HISTORY_CAP sob demanda
async function fetchGirosFromAPI(limit = REALTIME_HISTORY_CAP, timeoutMs = 20000) {
    if (!API_CONFIG.enabled) {
        console.log('⚠️ API_CONFIG.enabled = false - não buscará giros do servidor');
        return null;
    }
    
    try {
        const resolvedLimit = clampInt(limit, 1, REALTIME_HISTORY_CAP);
        const resolvedTimeout = Number.isFinite(Number(timeoutMs)) ? Math.max(5000, Math.floor(Number(timeoutMs))) : 20000;
        console.log('📥 INICIANDO BUSCA DE GIROS DO SERVIDOR...');
        console.log('   URL:', `${API_CONFIG.baseURL}/api/giros?limit=${resolvedLimit}`);
        console.log('   Timeout:', `${Math.round(resolvedTimeout / 1000)} segundos`);
        
        const startTime = Date.now();
        
        // Para 10k, pode demorar mais (especialmente em cold start / conexão lenta)
        const response = await fetchWithTimeout(`${API_CONFIG.baseURL}/api/giros?limit=${resolvedLimit}`, {}, resolvedTimeout);
        
        const elapsedTime = ((Date.now() - startTime) / 1000).toFixed(2);
        console.log(`⏱️ Tempo de resposta: ${elapsedTime}s`);
        
        if (response.ok) {
            const data = await response.json();
            console.log('✅ Resposta recebida com sucesso!');
            console.log('   data.success:', data.success);
            console.log('   data.data existe?', !!data.data);
            console.log('   data.data.length:', data.data ? data.data.length : 'N/A');
            
            if (data.success && data.data) {
                console.log(`%c✅ SERVIDOR RETORNOU ${data.data.length} GIROS!`, 'color: #00ff00; font-weight: bold; font-size: 14px;');
                console.log('   Primeiro giro (mais recente):', data.data[0]);
                console.log('   Último giro (mais antigo):', data.data[data.data.length - 1]);
                return data.data;
            } else {
                console.log('⚠️ Resposta do servidor sem dados válidos');
                console.log('   Estrutura recebida:', Object.keys(data));
            }
        } else {
            console.log('❌ Resposta com erro do servidor');
            console.log('   Status:', response.status);
            console.log('   StatusText:', response.statusText);
        }
    } catch (error) {
        console.log('❌ ERRO AO BUSCAR GIROS DO SERVIDOR!');
        console.log('   Tipo de erro:', error.name);
        console.log('   Mensagem:', error.message);
        console.log('   Stack:', error.stack);
        
        // Não mostrar erro assustador se for timeout - servidor pode estar ocupado
        if (error.message.includes('Timeout')) {
            console.log('⏳ Servidor ocupado - Continuará sincronizando em tempo real...');
        } else {
            console.warn('⚠️ Erro ao buscar giros do servidor:', error.message);
        }
    }
    return null;
}

// ═══════════════════════════════════════════════════════════════════════════════
// 📦 HISTÓRICO PARA SIMULAÇÃO/OTIMIZAÇÃO (até 10k, sob demanda)
// ═══════════════════════════════════════════════════════════════════════════════
// Reutiliza cachedHistory do modo real quando suficiente; busca do servidor apenas se o usuário
// pedir mais do que temos em memória (ex.: cache ainda não alcançou o limite).
const SIMULATION_SERVER_HISTORY_CAP = REALTIME_HISTORY_CAP;
const SIMULATION_SERVER_HISTORY_TIMEOUT_MS = 45000; // 45s: tolera cold start / payload maior
const SIMULATION_HISTORY_CACHE_TTL_MS = 15000;      // 15s: evita re-fetch em cliques seguidos
let simulationHistoryCache = { ts: 0, history: null };

async function getServerHistoryForSimulation() {
    if (!API_CONFIG.enabled) return null;
    const now = Date.now();
    if (simulationHistoryCache.history && (now - simulationHistoryCache.ts) < SIMULATION_HISTORY_CACHE_TTL_MS) {
        return simulationHistoryCache.history;
    }
    const serverGiros = await fetchGirosFromAPI(SIMULATION_SERVER_HISTORY_CAP, SIMULATION_SERVER_HISTORY_TIMEOUT_MS);
    if (Array.isArray(serverGiros) && serverGiros.length > 0) {
        simulationHistoryCache = { ts: now, history: serverGiros };
        return serverGiros;
    }
    return null;
}

async function getHistorySourceForPastRuns(requestedLimit) {
    const localHistory = Array.isArray(cachedHistory) ? cachedHistory : [];
    const localLen = localHistory.length || 0;
    const req = Number(requestedLimit);

    const wantsMoreThanLocal = Number.isFinite(req) && req > localLen;
    if (wantsMoreThanLocal) {
        const serverHistory = await getServerHistoryForSimulation();
        if (Array.isArray(serverHistory) && serverHistory.length > 0) {
            return serverHistory;
        }
    }
    return localHistory;
}

// Salvar giros no servidor
async function saveGirosToAPI(giros) {
    if (!API_CONFIG.enabled || !apiStatus.isOnline) return false;
    
    const girosArray = Array.isArray(giros) ? giros : [giros];
    
    try {
        console.log(`📤 Enviando ${girosArray.length} giro(s) para o servidor...`);
        const response = await fetchWithTimeout(`${API_CONFIG.baseURL}/api/giros`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(giros)
        });
        
        if (response.ok) {
            const data = await response.json();
            console.log(`%c✅ ${data.message || 'Giros salvos com sucesso!'}`, 'color: #00ff00; font-weight: bold;');
            console.log(`📊 Total no servidor: ${data.totalGiros || '?'} giros`);
            return true;
        }
    } catch (error) {
        console.warn('%c⚠️ Erro ao salvar giros no servidor:', 'color: #ff9900; font-weight: bold;', error.message);
    }
    return false;
}

